/**
 * Module dependencies.
 */

var parseUrl = require('parseurl');
var qs = require('qs');

/**
 * Query string parsing middleware.
 *
 * This middleware parses the URL query string into a JavaScript object
 * and makes it available as `req.query`. It uses the `qs` module for
 * parsing, which supports nested objects and arrays in the query string.
 *
 * @param {Object} options
 * @return {Function} middleware
 * @api public
 */

module.exports = function query(options) {
  var opts = Object.create(options || null);
  var queryparse = qs.parse;

  if (opts.allowPrototypes === undefined) {
    // Back-compat for qs module
    opts.allowPrototypes = true;
  }

  return function query(req, res, next) {
    if (!req.query) {
      var val = parseUrl(req).query;
      req.query = val ? queryparse(val, opts) : {};
    }

    next();
  };
};